## 二、OpenAI Function Calling 完整代码

### 最小示例：查天气

```python
from openai import OpenAI
import json

client = OpenAI(api_key="your-api-key")

# 1. 定义工具
tools = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "获取城市天气",
            "parameters": {
                "type": "object",
                "properties": {
                    "city": {"type": "string", "description": "城市名称"}
                },
                "required": ["city"]
            }
        }
    }
]

# 2. 用户输入
user_message = "北京今天多少度？"

# 3. 第一次调用 LLM
response = client.chat.completions.create(
    model="gpt-4o-mini",
    messages=[{"role": "user", "content": user_message}],
    tools=tools,
    tool_choice="auto"
)

# 4. 解析 LLM 的回复
message = response.choices[0].message

if message.tool_calls:
    # LLM 决定调用工具
    tool_call = message.tool_calls[0]
    function_name = tool_call.function.name
    arguments = json.loads(tool_call.function.arguments)

    print(f"LLM 决定调用：{function_name}")
    print(f"参数：{arguments}")

    # 5. 执行工具
    if function_name == "get_weather":
        weather = get_weather(arguments["city"])

    # 6. 把结果返回给 LLM，获取最终回答
    final_response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {"role": "user", "content": user_message},
            message,
            {
                "role": "tool",
                "tool_call_id": tool_call.id,
                "content": json.dumps(weather)
            }
        ]
    )

    print("最终回答：", final_response.choices[0].message.content)
else:
    print("LLM 直接回答：", message.content)

# 模拟天气 API
def get_weather(city):
    weather_db = {
        "北京": {"temp": 25, "weather": "晴天"},
        "上海": {"temp": 28, "weather": "多云"},
        "深圳": {"temp": 30, "weather": "雨天"}
    }
    return weather_db.get(city, {"temp": 20, "weather": "未知"})
```

### 运行结果

```
LLM 决定调用：get_weather
参数：{'city': '北京'}
最终回答： 北京今天25度，晴天，适合户外活动。
```

