## 三、实战：多工具 Agent

### 场景：智能助手

```python
from openai import OpenAI
import json

client = OpenAI(api_key="your-api-key")

# 1. 定义多个工具
tools = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "查询城市天气",
            "parameters": {
                "type": "object",
                "properties": {
                    "city": {"type": "string", "description": "城市名称"}
                },
                "required": ["city"]
            }
        }
    },
    {
        "type": "function",
        "function": {
            "name": "get_news",
            "description": "搜索最新新闻",
            "parameters": {
                "type": "object",
                "properties": {
                    "topic": {"type": "string", "description": "新闻主题"}
                },
                "required": ["topic"]
            }
        }
    },
    {
        "type": "function",
        "function": {
            "name": "calculate",
            "description": "数学计算器",
            "parameters": {
                "type": "object",
                "properties": {
                    "expression": {"type": "string", "description": "数学表达式，如 2+3*5"}
                },
                "required": ["expression"]
            }
        }
    }
]

# 2. 模拟工具实现
def get_weather(city):
    return {"city": city, "temp": 22, "weather": "晴天"}

def get_news(topic):
    return {"topic": topic, "headlines": [f"{topic}的最新消息...", "..."]}

def calculate(expression):
    try:
        result = eval(expression)
        return {"expression": expression, "result": result}
    except:
        return {"error": "计算错误"}

tool_map = {"get_weather": get_weather, "get_news": get_news, "calculate": calculate}

# 3. Agent 主循环
def run_agent(user_input, max_turns=5):
    messages = [{"role": "user", "content": user_input}]

    for turn in range(max_turns):
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=tools,
            tool_choice="auto"
        )

        message = response.choices[0].message

        if not message.tool_calls:
            return message.content

        for tool_call in message.tool_calls:
            function_name = tool_call.function.name
            arguments = json.loads(tool_call.function.arguments)

            print(f"[Turn {turn+1}] 调用工具：{function_name}({arguments})")

            if function_name in tool_map:
                result = tool_map[function_name](**arguments)
            else:
                result = {"error": f"未知工具：{function_name}"}

            messages.append({
                "role": "tool",
                "tool_call_id": tool_call.id,
                "content": json.dumps(result)
            })

# 4. 测试
print(run_agent("北京天气怎么样？和上海比呢？"))
print("---")
print(run_agent("计算 (100 + 200) / 3"))
print("---")
print(run_agent("给我看看最新的AI新闻"))
```

